function handleVideoEnded(index) {
    // Intro Sequence: A -> B -> C(x3) -> D
    if (index === 0) playVid(1); // A done -> B
    else if (index === 1) playVid(2); // B done -> C
    else if (index === 2) {
        // New logic: if message sent during C, loop C unless it was sent in the last 1s
        if (messageSentDuringVid === 2) {
            if (isLateSend) {
                playVid(3); // Proceed to D
            } else {
                playVid(2); // Loop C forever
            }
        } else {
            // Standard intro progression if no message active
            cLoopCount++;
            if (cLoopCount < 3) playVid(2);
            else playVid(3);
        }
    }
    // Idle/Interaction Logic
    else if (index === 3) { // D ended
        if (messageSentDuringVid === 3) {
            if (isLateSend) playVid(4); // Play E
            else playVid(6); // Play G
            messageSentDuringVid = null;
        } else {
            playVid(3); // Loop D indefinitely until message
        }
    }
    else if (index === 4) { // E ended
        if (messageSentDuringVid === 4) {
            if (isLateSend) {
                isLateSend = false; // Reset late flag
                playVid(4); // Loop E once more
            } else {
                playVid(6); // Play G
                messageSentDuringVid = null;
            }
        } else if (messageSentDuringVid === 3 && isLateSend) {
             // We came from D late, now play G
             playVid(6);
             messageSentDuringVid = null;
        } else {
            playVid(3); // Default back to D
        }
    }
    else if (index === 6) { // G ended
        playVid(3); // Back to D loop
    }
}

