    const configRows = document.querySelectorAll('.config-row');
    const newConfig = Array.from(configRows).map(row => ({
        id: row.dataset.id,
        order: parseInt(row.querySelector('.order-input').value),
        loop: row.querySelector('.loop-input').checked
    }));

