}

function renderVideoConfig() {
    const list = document.getElementById('video-config-list');
    list.innerHTML = '';
    videoConfig.sort((a,b) => a.order - b.order).forEach(conf => {
        const div = document.createElement('div');
        div.className = 'config-row flex items-center gap-2 bg-white/5 p-2 rounded-lg border border-white/10';
        div.dataset.id = conf.id;
        div.innerHTML = `
            <span class="text-white font-bold w-6 text-center">${conf.id}</span>
            <input type="number" class="order-input w-12 bg-black/20 border border-white/20 rounded px-1 text-xs text-white" value="${conf.order}">
            <label class="flex items-center gap-1 text-[10px] text-white/60">
                <input type="checkbox" class="loop-input" ${conf.loop ? 'checked' : ''}> Loop
            </label>
            <button onclick="this.parentElement.remove()" class="ml-auto text-red-400 hover:text-red-300 text-xs">
                <i class="fa-solid fa-trash"></i>
            </button>
        `;
        list.appendChild(div);
    });
}

function addVideoConfig() {
    const name = prompt("Enter Video Name (e.g. H):");
    if (!name) return;
    const nextOrder = videoConfig.length > 0 ? Math.max(...videoConfig.map(c => c.order)) + 1 : 1;
    videoConfig.push({ id: name.toUpperCase(), order: nextOrder, loop: false });
    renderVideoConfig();
}

